import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { careerAPI, getAIRecommendation } from '../services/api';
import {
  RadarChart, Radar, PolarGrid, PolarAngleAxis,
  ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Cell
} from 'recharts';
import { Brain, TrendingUp, DollarSign } from 'lucide-react';

const COLORS = ['#4f6ef7', '#8b5cf6', '#06b6d4'];

export default function ResultsPage() {
  const { user } = useAuth();
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const runPrediction = async () => {
    setLoading(true);
    setError('');

    try {
      const quizScores = JSON.parse(localStorage.getItem('quiz_scores') || '{}');

      const payload = {
        skills: user?.skills || [],
        interests: user?.interests || [],
        education_level: user?.education_level || "Bachelor's Degree",
        gpa: parseFloat(user?.gpa) || 3.0,
        personality_type: user?.personality_type || 'Analytical',
        experience_years: parseInt(user?.experience_years) || 0,
        quiz_scores: quizScores,
      };

      // ✅ Traditional ML
      const res1 = await careerAPI.predict(payload);

      // ✅ AI (safe fallback)
      let aiData = null;
      try {
        const res2 = await getAIRecommendation(quizScores);

        try {
          aiData = JSON.parse(res2.data.result);
        } catch {
          aiData = { raw: res2.data.result };
        }
      } catch (err) {
        console.log("AI failed:", err);
        aiData = {
          raw: "⚠️ AI unavailable (Quota exceeded or API issue). Try again later."
        };
      }

      setResults({
        traditional: res1.data.recommendations,
        ai: aiData
      });

    } catch (e) {
      console.error(e);
      setError(
        e.response?.data?.detail ||
        'Prediction failed. Please complete your profile first.'
      );
    } finally {
      setLoading(false);
    }
  };

  const barData = results?.traditional?.map((r) => ({
    name: r.career_name?.split(' ').slice(0, 2).join(' '),
    match: r.match_percentage,
  })) || [];

  return (
    <div className="text-white max-w-6xl mx-auto p-4">

      {/* HEADER */}
      <div className="flex justify-between items-center mb-6">
        <h1 className="text-3xl font-bold flex items-center gap-2">
          <Brain /> Career Recommendations
        </h1>

        <button
          onClick={runPrediction}
          disabled={loading}
          className="px-5 py-2 rounded-lg bg-gradient-to-r from-blue-500 to-purple-500 font-semibold hover:opacity-90"
        >
          {loading ? "Analyzing..." : "Get AI Predictions"}
        </button>
      </div>

      {error && <div className="text-red-400 mb-4">{error}</div>}

      {/* EMPTY */}
      {!results && !loading && (
        <div className="text-center py-20 text-white/50">
          Click "Get AI Predictions" to start
        </div>
      )}

      {results?.traditional && (
        <>
          {/* TOP CARDS */}
          <div className="grid md:grid-cols-3 gap-5 mb-8">
            {results.traditional.map((r, i) => (
              <div key={i} className="p-5 rounded-xl bg-white/5 border border-white/10">
                <h3 className="text-lg font-bold">{r.career_name}</h3>

                <p className="text-sm mt-2 text-blue-400">
                  Match: {r.match_percentage}%
                </p>

                <p className="text-sm text-green-400 flex items-center gap-1">
                  <DollarSign size={14} /> ${(r.avg_salary / 1000).toFixed(0)}K/year
                </p>

                <Link
                  to={`/roadmap/${encodeURIComponent(r.career_name)}`}
                  className="block mt-3 text-sm text-purple-400"
                >
                  View Roadmap →
                </Link>
              </div>
            ))}
          </div>

          {/* BAR CHART */}
          <div className="mb-8 p-4 bg-white/5 rounded-xl border border-white/10">
            <h3 className="mb-3 font-semibold">Match Comparison</h3>

            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={barData}>
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="match">
                  {barData.map((_, i) => (
                    <Cell key={i} fill={COLORS[i]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* SKILLS */}
          <div className="mb-8 p-4 bg-white/5 rounded-xl border border-white/10">
            <h3 className="mb-3 font-semibold">Required Skills</h3>

            <div className="flex flex-wrap gap-2">
              {(results.traditional[0]?.required_skills || []).map(skill => (
                <span
                  key={skill}
                  className="px-3 py-1 bg-white/10 rounded-lg text-sm"
                >
                  {skill}
                </span>
              ))}
            </div>
          </div>

          {/* 🤖 AI SECTION (IMPROVED UI) */}
          {results.ai && (
            <div className="p-5 rounded-xl bg-gradient-to-br from-purple-900/40 to-blue-900/40 border border-purple-500/20">
              <h2 className="text-xl font-bold mb-4 flex items-center gap-2">
                🤖 AI Career Insight
              </h2>

              {results.ai.raw ? (
                <p className="text-sm text-white/70">
                  {results.ai.raw}
                </p>
              ) : (
                <div className="space-y-4">

                  <div>
                    <h4 className="font-semibold text-blue-400">Streams</h4>
                    <ul className="list-disc ml-5 text-sm">
                      {results.ai.streams?.map((s, i) => <li key={i}>{s}</li>)}
                    </ul>
                  </div>

                  <div>
                    <h4 className="font-semibold text-purple-400">Courses</h4>
                    <ul className="list-disc ml-5 text-sm">
                      {results.ai.courses?.map((c, i) => <li key={i}>{c}</li>)}
                    </ul>
                  </div>

                  <div>
                    <h4 className="font-semibold text-green-400">Reason</h4>
                    <p className="text-sm">{results.ai.reason}</p>
                  </div>

                  <div>
                    <h4 className="font-semibold text-yellow-400">Skills to Learn</h4>
                    <div className="flex flex-wrap gap-2 mt-2">
                      {results.ai.skills?.map((s, i) => (
                        <span key={i} className="px-2 py-1 bg-yellow-500/20 rounded text-xs">
                          {s}
                        </span>
                      ))}
                    </div>
                  </div>

                </div>
              )}
            </div>
          )}
        </>
      )}
    </div>
  );
}
